import React, { useState } from 'react';
import Logo from './Logo.png'; 
import Menu, { Lunch } from './Menu'; 

const gold = '#D4AF37';
const darkGrey = '#1A1A1A';

// --- MOBILE-STYLE WIG STORE ---
const WigStore = () => {
  const wigs = [
    { name: "2*4 T-Closure", price: "17,500", type: "Hair Blend" },
    { name: "5*5 Closure", price: "25,500", type: "Premium Fibre" },
    { name: "Raw Cambodian", price: "85,000", type: "Human Hair" }
  ];

  return (
    <div style={{ padding: '0 10px' }}>
      {wigs.map((wig) => (
        <div key={wig.name} style={{ 
          display: 'flex', 
          backgroundColor: '#111', 
          borderRadius: '12px', 
          marginBottom: '12px', 
          padding: '10px',
          alignItems: 'center',
          border: '1px solid #222'
        }}>
          <div style={{ width: '80px', height: '80px', backgroundColor: '#000', borderRadius: '8px', marginRight: '15px' }}></div>
          <div style={{ flex: 1 }}>
            <h4 style={{ fontSize: '0.9rem', margin: '0 0 4px 0', color: '#fff' }}>{wig.name}</h4>
            <p style={{ fontSize: '0.7rem', color: gold, margin: 0 }}>{wig.type}</p>
            <div style={{ fontSize: '0.9rem', fontWeight: 'bold', marginTop: '5px' }}>₦{wig.price}</div>
          </div>
          <button style={{ backgroundColor: gold, border: 'none', borderRadius: '20px', padding: '5px 15px', fontSize: '0.7rem', fontWeight: 'bold' }}>ADD</button>
        </div>
      ))}
    </div>
  );
};

function App() {
  const [activeCategory, setActiveCategory] = useState('Wigs');

  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', color: '#fff', fontFamily: 'system-ui, sans-serif' }}>
      
      {/* 1. TOP BRAND HEADER (Sticky) */}
      <header style={{ padding: '15px', borderBottom: '1px solid #111', display: 'flex', justifyContent: 'space-between', alignItems: 'center', position: 'sticky', top: 0, backgroundColor: '#000', zIndex: 100 }}>
        <img src={Logo} alt="Logo" style={{ height: '35px' }} />
        <div style={{ display: 'flex', gap: '15px' }}>
          <span>👤</span>
          <span>🛒 <small style={{ background: gold, borderRadius: '50%', padding: '2px 5px', fontSize: '0.6rem', color: '#000' }}>0</small></span>
        </div>
      </header>

      {/* 2. PROMO BANNER (Big & Impactful) */}
      <div style={{ width: '100%', height: '160px', backgroundColor: '#800000', display: 'flex', flexDirection: 'column', justifyContent: 'center', padding: '0 20px', backgroundImage: 'linear-gradient(rgba(0,0,0,0.5), rgba(0,0,0,0.5))' }}>
        <h2 style={{ fontSize: '1.4rem', margin: '0 0 5px 0' }}>TASTE & STYLE.</h2>
        <p style={{ fontSize: '0.75rem', margin: 0, opacity: 0.8 }}>LAGOS' FAVORITE LUXURY HAIR & CHOPS.</p>
      </div>

      {/* 3. BUSINESS INFO BLOCK */}
      <div style={{ padding: '20px' }}>
        <h1 style={{ fontSize: '1.2rem', margin: '0 0 5px 0' }}>Àmí by T - Ikeja Shop</h1>
        <div style={{ fontSize: '0.75rem', color: '#888', display: 'flex', alignItems: 'center', gap: '5px' }}>
          <span style={{ color: '#00FF00' }}>● Opened</span> <span>Closes today at 08:00 PM</span>
        </div>
        
        {/* APP-STYLE BUTTONS */}
        <div style={{ display: 'flex', gap: '10px', marginTop: '20px' }}>
          <button style={{ flex: 1, padding: '12px', borderRadius: '25px', border: 'none', backgroundColor: '#eee', fontWeight: 'bold' }}>Pickup</button>
          <button style={{ flex: 1, padding: '12px', borderRadius: '25px', border: '1px solid #333', backgroundColor: 'transparent', color: '#fff' }}>Delivery</button>
        </div>
      </div>

      {/* 4. SEARCH BAR */}
      <div style={{ padding: '0 20px 20px' }}>
        <div style={{ backgroundColor: '#1A1A1A', borderRadius: '25px', padding: '10px 20px', color: '#666', fontSize: '0.85rem' }}>
          🔍 Search catalog...
        </div>
      </div>

      {/* 5. HORIZONTAL PILL NAVIGATION */}
      <div style={{ display: 'flex', gap: '10px', overflowX: 'auto', padding: '0 20px 20px', scrollbarWidth: 'none' }}>
        {['Small Chops', 'Office Lunch', 'Wigs', 'About'].map((item) => (
          <button 
            key={item} 
            onClick={() => setActiveCategory(item)}
            style={{ 
              whiteSpace: 'nowrap',
              padding: '8px 20px', 
              borderRadius: '20px', 
              border: 'none',
              backgroundColor: activeCategory === item ? '#fff' : '#1A1A1A',
              color: activeCategory === item ? '#000' : '#fff',
              fontSize: '0.8rem',
              fontWeight: '600'
            }}
          >
            {item}
          </button>
        ))}
      </div>

      {/* 6. CONTENT AREA */}
      <main style={{ paddingBottom: '100px' }}>
        <h3 style={{ padding: '0 20px 15px', fontSize: '1.1rem' }}>{activeCategory}</h3>
        {activeCategory === 'Wigs' && <WigStore />}
        {activeCategory === 'Small Chops' && <Menu />}
        {activeCategory === 'Office Lunch' && <Lunch />}
      </main>

    </div>
  );
}

export default App;
